SELECT COUNT(*) 
FROM volcanoes 
WHERE last_eruption_year >= strftime('%Y', 'now') - 50;

SELECT COUNT(volcano_name) AS active_volcanoes_count
FROM volcanoes
WHERE volcano_status = 'active';

SELECT volcano_name, last_eruption_year
FROM volcanoes
ORDER BY last_eruption_year DESC;

SELECT volcano_status, COUNT(volcano_status) AS volcano_count
FROM volcanoes
GROUP BY volcano_status;

SELECT COUNT(*) AS total_volcanoes
FROM volcanoes
WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'YourCountryNameHere');
